// GlbTOKEN i18n — instant client-side translation, no reload
// English text → {lang: translated text} lookup
// Generated for: zh-CN, ru, ja, de

const TRANS = {};

let curLang = localStorage.getItem('gt_lang') || 'en';

function switchLanguage(lang) {
  curLang = lang;
  localStorage.setItem('gt_lang', lang);
  // Reload so all text (including mixed-content with links) is properly translated
  location.reload();
}

function translatePage() {
  var walker = document.createTreeWalker(document.body, 4, null, false);
  var nodes = [];
  while (walker.nextNode()) nodes.push(walker.currentNode);
  for (var i = 0; i < nodes.length; i++) {
    var n = nodes[i];
    if (!n.parentNode) continue;
    if (n.parentNode.closest && n.parentNode.closest('.notranslate,[translate="no"],script,style,svg,code,pre,option,.lang-selector,.lang-menu,.lang-option,.nav-logo,.logo-glb,.logo-token,.trust-badge,.star,.tm-dot,.tm-arrow,.copying,select,input,textarea,.lang-btn,.lang-btn-mobile')) continue;
    var text = n.textContent.trim();
    if (!text || text.length < 2 || text.length > 2000) continue;
    if (TRANS[text] && TRANS[text][curLang]) {
      n.textContent = TRANS[text][curLang];
    }
  }
  // Also handle data-i18n elements with HTML content
  document.querySelectorAll('[data-i18n]').forEach(function(el) {
    var key = el.getAttribute('data-i18n');
    // First try I18N_MIXED for HTML-safe translation (preserves child elements)
    if (typeof I18N_MIXED !== 'undefined' && I18N_MIXED[key] && I18N_MIXED[key][curLang]) {
      el.innerHTML = I18N_MIXED[key][curLang];
    }
    // Fallback to plain text translation
    else if (TRANS[key] && TRANS[key][curLang]) {
      el.textContent = TRANS[key][curLang];
    }
  });
}

function updateLangUI(lang) {
  document.querySelectorAll('.lang-option').forEach(function(el) {
    el.classList.toggle('active', el.getAttribute('data-lang') === lang);
  });
  var lbl = document.getElementById('currentLangLabel');
  if (lbl) lbl.textContent = lang === 'zh-CN' ? '中文' : lang === 'en' ? 'EN' : lang === 'ru' ? 'RU' : lang === 'ja' ? '日' : 'DE';
  var lm = document.getElementById('langMenu');
  if (lm) lm.classList.remove('open');
}

// Apply on every page load — immediately translate if a saved language exists
(function() {
  var saved = localStorage.getItem('gt_lang');
  if (saved && saved !== 'en') {
    curLang = saved;
    function doTranslate() { translatePage(); updateLangUI(saved); }
    if (document.readyState === 'loading') {
      document.addEventListener('DOMContentLoaded', doTranslate);
    } else {
      doTranslate();
    }
  }
})();

// Also translate after page navigation (bfcache)
window.addEventListener('pageshow', function(e) {
  // e.persisted is true when page is served from bfcache
  var saved = localStorage.getItem('gt_lang');
  if (saved && saved !== 'en') {
    curLang = saved;
    translatePage();
    updateLangUI(saved);
  }
});

